+        let large_val = (1_u64 << 53) + 42;
+        let arr = UFuncArray::from_storage(vec![1], ArrayStorage::U64(vec![large_val]))
+            .expect("from_storage");
+        let out = arr.pad(&[(1, 1)], -1.0).expect("pad");
+        assert!(!out.has_integer_sidecar());
+        assert!(out.to_storage().is_err());
+    }
